## Resource Manager

### Stack

```hcl
resource "oci_resourcemanager_stack" "stack" {
  compartment_id = var.compartment_id
  display_name  = "my-stack"

  terraform_version = "1.6.x"

  config_source {
    zip_file_base64encoded = base64encode(file("terraform.zip"))
  }
}
```

### Plan Job

```hcl
resource "oci_resourcemanager_job" "plan" {
  stack_id = oci_resourcemanager_stack.stack.id
  operation = "PLAN"

  apply_job_plan_resolution {
    is_auto_approved = true
  }
}
```

### Apply Job

```hcl
resource "oci_resourcemanager_job" "apply" {
  stack_id = oci_resourcemanager_stack.stack.id
  operation = "APPLY"
}
```

### Destroy Job

```hcl
resource "oci_resourcemanager_job" "destroy" {
  stack_id = oci_resourcemanager_stack.stack.id
  operation = "DESTROY"
}
```
